             match(LHS, m_Select(m_Value(A), m_Value(B), m_Value(C))) &&
             match(RHS, m_Select(m_Specific(A), m_Specific(C), m_Specific(B)))) {
    Cond = A;
    True = simplifyBinOp(Opcode, B, C, FMF, Q);
    False = True;
  } else if (LHSIsSelect && RHSIsSelect && match(D, m_Not(m_Specific(A)))) {
